cartSetup.query:
mutation AuthoritativeLifecycleCartSetup($functionId: String!) {
  cartTransformCreate(functionId: $functionId) {
    cartTransform { id }
    userErrors { field message code }
  }
}

functionValidationDecisionPreflight.query:
query FunctionValidationDecisionPreflight($after: String) {
  validations(first: 250, after: $after) {
    nodes {
      id
      enabled
      shopifyFunction {
        id
      }
    }
    pageInfo {
      hasNextPage
      endCursor
    }
  }
}

validationFunctionHydrate.query:
query FunctionHydrateById($id: String!) {
  shopifyFunction(id: $id) {
    id
    title
    apiType
    description
    appKey
    app {
      __typename
      id
      title
      apiKey
    }
  }
}

functionCartTransformDecisionPreflight.query:
query FunctionCartTransformDecisionPreflight {
  cartTransforms(first: 1) {
    nodes {
      id
      functionId
    }
  }
}

